// WebGPU compat test #4 — the points-placement question. Renders ONE point
// quad using the EXACT expansion line from aeon-3d's POINT_WGSL
// (house-renderer-webgpu.ts), with a center baked at NDC (0.3,-0.4), and checks
// the red quad's centroid lands where that center projects to screen. If Deno
// and monster (both wgpu) agree AND the centroid hits the analytic projection,
// the points math is correct on wgpu — i.e. the WebKit misplacement is a
// WebKit-impl bug, not an aeon-3d code bug.
const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();
const W = 64, H = 64;
const tex = device.createTexture({
  size: { width: W, height: H },
  format: 'rgba8unorm',
  usage: GPUTextureUsage.RENDER_ATTACHMENT | GPUTextureUsage.COPY_SRC,
});
const shader = device.createShaderModule({
  code: `
    @vertex fn vs(@builtin(vertex_index) i: u32) -> @builtin(position) vec4f {
      var corners = array<vec2f,4>(vec2f(0.,0.), vec2f(1.,0.), vec2f(0.,1.), vec2f(1.,1.));
      let corner = corners[i];
      var clip = vec4f(0.3, -0.4, 0.0, 1.0);   // a point center projected to NDC
      let sizePx = 16.0;
      let viewport = vec2f(64.0, 64.0);
      // EXACT line from POINT_WGSL:
      clip = vec4f(clip.xy + (corner - vec2f(0.5)) * sizePx * (2.0 / viewport) * clip.w, clip.zw);
      return clip;
    }
    @fragment fn fs() -> @location(0) vec4f { return vec4f(1.,0.,0.,1.); }
  `,
});
const pipeline = device.createRenderPipeline({
  layout: 'auto',
  vertex: { module: shader, entryPoint: 'vs' },
  fragment: { module: shader, entryPoint: 'fs', targets: [{ format: 'rgba8unorm' }] },
  primitive: { topology: 'triangle-strip' },
});
const enc = device.createCommandEncoder();
const pass = enc.beginRenderPass({
  colorAttachments: [{ view: tex.createView(), loadOp: 'clear', storeOp: 'store', clearValue: { r: 0, g: 0, b: 0, a: 1 } }],
});
pass.setPipeline(pipeline);
pass.draw(4);
pass.end();
const bpr = W * 4;
const rb = device.createBuffer({ size: bpr * H, usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ });
enc.copyTextureToBuffer({ texture: tex }, { buffer: rb, bytesPerRow: bpr }, { width: W, height: H });
device.queue.submit([enc.finish()]);
await rb.mapAsync(GPUMapMode.READ);
const px = new Uint8Array(rb.getMappedRange());
let sx = 0, sy = 0, n = 0;
for (let y = 0; y < H; y++) for (let x = 0; x < W; x++) {
  const o = y * bpr + x * 4;
  if (px[o] > 200 && px[o + 1] < 50) { sx += x; sy += y; n++; }
}
rb.unmap();
out.count = n;
out.cx = n ? Math.round(sx / n) : -1;
out.cy = n ? Math.round(sy / n) : -1;
// analytic projection of NDC (0.3,-0.4): x=(0.3*.5+.5)*64=41.6, y=(0.5-(-0.4)*0.5)*64=44.8
out.expectX = 42;
out.expectY = 45;
out.centered = Math.abs(out.cx - 42) <= 1 && Math.abs(out.cy - 45) <= 1;
console.log('__RESULT__ ' + JSON.stringify(out));
